#!/usr/bin/env node
// RZI Camp - Prebuild: restore src/ if missing
const fs = require('fs');
const cp = require('child_process');
const path = require('path');

const mainFile = path.join(__dirname, 'src', 'main.jsx');
if (!fs.existsSync(mainFile)) {
  console.log('🔧 src/ missing - restoring...');
  const data = Buffer.from('', 'base64');
  fs.writeFileSync('/tmp/rzi_src.tar.gz', data);
  cp.execSync('tar -xzf /tmp/rzi_src.tar.gz -C ' + __dirname);
  fs.unlinkSync('/tmp/rzi_src.tar.gz');
  console.log('✅ src/ restored - ' + fs.readdirSync(path.join(__dirname,'src','pages')).length + ' pages');
} else {
  console.log('✅ src/ already present');
}
